SELECT topic_name
FROM training_topics
WHERE topic_status = 'Active';

SELECT COUNT(*) AS active_topics_count
FROM training_topics
WHERE topic_status = 'Active';

SELECT description
FROM training_topics
WHERE topic_id = 0;

SELECT attended, COUNT(attendance_id) AS number_of_participants
FROM attendances
GROUP BY attended;

SELECT COUNT(*) AS experienced_supervisors
FROM supervisors
WHERE experience > 10;

SELECT supervisor_name, experience
FROM supervisors
ORDER BY experience DESC;

SELECT supervisor_name
FROM supervisors
WHERE experience = (SELECT MAX(experience) FROM supervisors);
